+    #[test]
+    fn lerp_u8_blends_correctly() {
+        assert_eq!(super::lerp_u8(0, 255, 0.0), 0);
+        assert_eq!(super::lerp_u8(0, 255, 1.0), 255);
+        assert_eq!(super::lerp_u8(0, 255, 0.5), 128);
